import re,sys
p="llvm/lib/Transforms/InstCombine/InstCombineCalls.cpp"
s=open(p).read()
start=s.find("case Intrinsic::fabs:")
end=s.find("case Intrinsic::ceil:", start)
block=s[start:end]
# Modify the fabs(select ...) handling to avoid dropping fabs; always push fabs into arms unless both arms non-negative.
new_block=re.sub(
    r'if \(match\(Arg, m_Select\(m_Value\(Cond\), m_Value\(TVal\), m_Value\(FVal\)\)\)\) \{.*?\n    \}',
    '''if (match(Arg, m_Select(m_Value(Cond), m_Value(TVal), m_Value(FVal)))) {
      // Conservatively transform: fabs(select Cond, TVal, FVal) --> select Cond, fabs(TVal), fabs(FVal)
